# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    handlers=[
        logging.FileHandler('app.log'),
        logging.StreamHandler()
    ]
)

logger = logging.getLogger(__name__)

app = Flask(__name__)

# Middleware to log requests
@app.before_request
def log_request_info():
    g.start_time = time.time()
    logger.info(f"Request: {request.method} {request.url}")
    logger.info(f"Headers: {dict(request.headers)}")
    
    if request.is_json:
        try:
            body_data = request.get_json()
            logger.info(f"Body: {json.dumps(body_data, indent=2)}")
        except Exception as e:
            logger.warning(f"Could not parse JSON body: {str(e)}")
    elif request.form:
        logger.info(f"Form data: {dict(request.form)}")
    elif request.data:
        logger.info(f"Raw data: {request.data.decode('utf-8')}")

# Middleware to log responses
@app.after_request
def log_response_info(response):
    duration = time.time() - g.start_time
    logger.info(f"Response: {response.status_code} - Duration: {duration:.3f}s")
    logger.info(f"Response headers: {dict(response.headers)}")
    return response

# Error handler
@app.errorhandler(Exception)
def handle_exception(e):
    logger.error(f"Unhandled exception: {str(e)}", exc_info=True)
    return jsonify({"error": "Internal server error"}), 500

# Authentication decorator
def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header:
            logger.warning("Authentication failed: No Authorization header")
            return jsonify({"error": "Authentication required"}), 401
        
        # Log authentication attempt
        logger.info(f"Auth attempt with token: {auth_header}")
        
        # Simulate authentication logic
        try:
            token = auth_header.split(' ')[1] if len(auth_header.split(' ')) > 1 else auth_header
            # In real app, validate token here
            if token == "valid_token":
                logger.info("Authentication successful")
                return f(*args, **kwargs)
            else:
                logger.warning(f"Authentication failed: Invalid token {token}")
                return jsonify({"error": "Invalid credentials"}), 401
        except Exception as e:
            logger.warning(f"Authentication error: {str(e)}")
            return jsonify({"error": "Authentication failed"}), 401
    
    return decorated_function

